const payload = $json.body && typeof $json.body === 'object' ? $json.body : $json;

function pick(...values) {
  return values.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
}

function normalizePath(value) {
  return String(value || '').trim().replace(/^\/+/, '');
}

function normalizeDir(value, fallback) {
  return String(value || fallback).trim().replace(/^\/+|\/+$/g, '');
}

function slug(value) {
  return String(value || 'output')
    .replace(/\.[^.]+$/, '')
    .replace(/^APPROVED_/i, '')
    .replace(/^PRD_/i, '')
    .replace(/\s+/g, '_')
    .replace(/[^A-Za-z0-9가-힣_-]+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '') || 'output';
}

function timestamp() {
  const d = new Date();
  const yy = String(d.getFullYear()).slice(-2);
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const hh = String(d.getHours()).padStart(2, '0');
  const mi = String(d.getMinutes()).padStart(2, '0');
  const ss = String(d.getSeconds()).padStart(2, '0');
  return yy + mm + dd + '_' + hh + mi + ss;
}

const targetOutputType = pick(payload.targetOutputType, 'service_scenario');
if (targetOutputType !== 'service_scenario') {
  throw new Error('This workflow only supports targetOutputType=service_scenario');
}

const sourcePrdPath = normalizePath(payload.sourcePrdPath);
const prdMarkdown = pick(payload.prdMarkdown, payload.prdContent, payload.content, '');

if (!sourcePrdPath) throw new Error('sourcePrdPath is required');
if (!String(prdMarkdown).trim()) throw new Error('prdMarkdown is required');

const sourcePrdName = slug(pick(payload.sourcePrdName, sourcePrdPath.split('/').pop(), 'approved_prd'));
const ts = timestamp();
const outputDir = normalizeDir(pick(payload.outputDir, payload.scenarioDir), 'scenario');
const outputFileName = 'SCN_' + sourcePrdName + '_' + ts + '.md';
const outputPath = outputDir + '/' + outputFileName;
const promptTemplate = normalizePath(pick(payload.promptTemplate, 'prompts/output/scenario/scenario-prompt-v1.md'));
const targetRegions = Array.isArray(payload.targetRegions) && payload.targetRegions.length
  ? payload.targetRegions
  : ['KR', 'US-CA', 'EU', 'UK', 'JP'];
const supportedLanguages = Array.isArray(payload.supportedLanguages) && payload.supportedLanguages.length
  ? payload.supportedLanguages
  : ['ko', 'en', 'ja'];

return [{ json: {
  action: 'agent2_output_generate',
  targetOutputType,
  sourcePrdPath,
  sourcePrdName,
  prdMarkdown: String(prdMarkdown).trim(),
  serviceType: pick(payload.serviceType, 'global_b2c_web_promotion'),
  targetRegions,
  supportedLanguages,
  outputLanguage: pick(payload.outputLanguage, 'ko'),
  promptTemplate,
  promptTemplateType: pick(payload.promptTemplateType, 'service_scenario'),
  businessPolicyOverrides: payload.businessPolicyOverrides || {},
  regionPolicyMatrix: payload.regionPolicyMatrix || [],
  documentVersion: pick(payload.documentVersion, '1.0'),
  generatedDate: pick(payload.generatedDate, new Date().toISOString().slice(0, 10)),
  requestedBy: pick(payload.requestedBy, 'web'),
  model: pick(payload.model, 'gpt-4o-mini'),
  temperature: Number(payload.temperature ?? 0.2),
  maxTokens: Number(payload.maxTokens || 12000),
  vercelBaseUrl: String(pick(payload.vercelBaseUrl, payload.baseUrl, 'https://howardchoi-nsus-pocax.vercel.app')).replace(/\/+$/, ''),
  outputPath,
  outputFileName,
  outputDir,
  timestamp: ts,
  receivedAt: new Date().toISOString()
}}];

const base = $('Normalize Service Scenario Request').item.json;
const promptResponse = $json;
const promptText = String(promptResponse.content || promptResponse.text || '').trim();

if (!promptText) {
  throw new Error('Scenario prompt file is empty or unreadable: ' + base.promptTemplate);
}

const userContent = [
  '# Service Scenario Generation Input',
  '',
  '## Request Metadata',
  '- targetOutputType: ' + base.targetOutputType,
  '- sourcePrdPath: ' + base.sourcePrdPath,
  '- serviceType: ' + base.serviceType,
  '- targetRegions: ' + base.targetRegions.join(', '),
  '- supportedLanguages: ' + base.supportedLanguages.join(', '),
  '- outputLanguage: ' + base.outputLanguage,
  '- documentVersion: ' + base.documentVersion,
  '- generatedDate: ' + base.generatedDate,
  '',
  '## Region Policy Matrix',
  JSON.stringify(base.regionPolicyMatrix || [], null, 2),
  '',
  '## Business Policy Overrides',
  JSON.stringify(base.businessPolicyOverrides || {}, null, 2),
  '',
  '## PRD Markdown',
  base.prdMarkdown
].join('\n');

return [{ json: {
  ...base,
  promptText,
  openAiRequestBody: {
    model: base.model,
    temperature: base.temperature,
    max_tokens: base.maxTokens,
    messages: [
      { role: 'system', content: promptText },
      { role: 'user', content: userContent }
    ]
  }
}}];

const base = $('Build OpenAI Request').item.json;
const llm = $json;

function extractText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(extractText).filter(Boolean).join('\n');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (typeof value.output_text === 'string') return value.output_text;
    if (typeof value.content === 'string') return value.content;
    if (Array.isArray(value.content)) return extractText(value.content);
    if (Array.isArray(value.output)) return extractText(value.output);
    if (value.message?.content) return extractText(value.message.content);
    if (value.choices) return extractText(value.choices);
  }
  return '';
}

const generatedContent = extractText(llm).trim();
if (!generatedContent) {
  throw new Error('LLM output did not contain service scenario markdown');
}

return [{ json: {
  success: true,
  targetOutputType: base.targetOutputType,
  path: base.outputPath,
  content: generatedContent,
  generatedContent,
  contentType: 'text/markdown; charset=utf-8',
  access: 'private',
  metadata: {
    sourcePrdPath: base.sourcePrdPath,
    sourcePrdName: base.sourcePrdName,
    promptTemplate: base.promptTemplate,
    targetRegions: base.targetRegions,
    supportedLanguages: base.supportedLanguages,
    outputLanguage: base.outputLanguage,
    model: base.model,
    generatedDate: base.generatedDate,
    documentVersion: base.documentVersion,
    createdAt: new Date().toISOString()
  }
}}];

const output = $('Normalize Scenario Output').item.json;
const save = $json || {};

return [{ json: {
  success: true,
  targetOutputType: output.targetOutputType,
  path: save.pathname || output.path,
  url: save.url || null,
  downloadUrl: save.downloadUrl || null,
  contentType: output.contentType,
  content: output.content,
  output: output.content,
  generatedContent: output.content,
  message: 'service scenario generated',
  savedAt: new Date().toISOString()
}}];
